// Fragment for review — will be embedded in social-image-render-workflow.json Choose Template node
const inputJsons = $input.all().map((item) => item.json ?? {});
const chainOut =
	inputJsons.find(
		(j) =>
			j &&
			((typeof j.text === 'string' && j.text.trim() !== '') ||
				(typeof j.message?.content === 'string' && j.message.content.trim() !== '')),
	) ??
	inputJsons.find((j) => j && j.templateId && j.payload && typeof j.payload === 'object') ??
	inputJsons[0] ??
	{};

const aiText = String(
	chainOut?.message?.content ??
		chainOut?.text ??
		(Array.isArray(chainOut?.data)
			? chainOut.data
					.map((x) => (typeof x === 'string' ? x : typeof x === 'object' ? JSON.stringify(x) : String(x)))
					.join('\n')
			: '') ??
		'',
);

const templatesSource = $('Get Templates').first().json;
const templates = Array.isArray(templatesSource.templates) ? templatesSource.templates : [];
if (!templates.length) {
	throw new Error('No templates returned from /api/templates');
}

const source = $('Prepare Test Input').first().json ?? {};
const goal = String(source.goal ?? '').trim();

const cleanJsonText = (text) => {
	const trimmed = String(text || '').trim();
	const fenced = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
	if (fenced) return fenced[1].trim();
	return trimmed;
};

let aiSelection = {};
if (
	chainOut &&
	typeof chainOut.templateId === 'string' &&
	chainOut.payload &&
	typeof chainOut.payload === 'object' &&
	!Array.isArray(chainOut.payload)
) {
	aiSelection = {
		templateId: chainOut.templateId,
		themeVariant: chainOut.themeVariant,
		payload: chainOut.payload,
	};
} else {
	try {
		const parsed = JSON.parse(cleanJsonText(aiText));
		if (parsed && typeof parsed === 'object') aiSelection = parsed;
	} catch (error) {
		aiSelection = {};
	}
}

const getTemplateId = (template) => template.id ?? template.templateId ?? template.slug;
const templatesById = new Map(templates.map((t) => [String(getTemplateId(t)), t]));

const requestedId =
	aiSelection.templateId !== undefined && aiSelection.templateId !== null
		? String(aiSelection.templateId)
		: '';

const fallbackTemplate = templates[0];
const selectedTemplate = templatesById.get(requestedId) ?? fallbackTemplate;
const selectedTemplateId = String(getTemplateId(selectedTemplate));

const variants = Array.isArray(selectedTemplate.themeVariants) ? selectedTemplate.themeVariants : [];
const requestedVariant = typeof aiSelection.themeVariant === 'string' ? aiSelection.themeVariant : '';
const themeVariant = variants.includes(requestedVariant)
	? requestedVariant
	: (variants[0] ?? requestedVariant ?? 'default');

const aiPayload =
	aiSelection.payload && typeof aiSelection.payload === 'object' && !Array.isArray(aiSelection.payload)
		? { ...aiSelection.payload }
		: {};

const aiPayloadByLower = {};
for (const [k, v] of Object.entries(aiPayload)) {
	aiPayloadByLower[String(k).toLowerCase()] = v;
}

const fieldDefsRaw = Array.isArray(selectedTemplate.fieldDefinitions)
	? selectedTemplate.fieldDefinitions
	: Array.isArray(selectedTemplate.fields)
		? selectedTemplate.fields
		: [];

const fieldKeys = fieldDefsRaw.map((f) => f.key ?? f.name ?? f.id).filter(Boolean);

const payload = {};

const str = (v) => (v === undefined || v === null ? '' : String(v));

for (const field of fieldDefsRaw) {
	const key = field.key ?? field.name ?? field.id;
	if (!key) continue;

	const lowerField = String(key).toLowerCase();
	const fromAi = aiPayload[key] ?? aiPayloadByLower[lowerField];

	if (fromAi !== undefined && fromAi !== null && str(fromAi).trim() !== '') {
		payload[key] = fromAi;
		continue;
	}

	const lowerKey = String(key).toLowerCase();
	if (lowerKey.includes('title')) {
		payload[key] = aiPayload.title ?? (goal ? goal.slice(0, 90) : 'Social post idea');
		continue;
	}
	if (lowerKey.includes('subtitle') || lowerKey.includes('tagline')) {
		payload[key] = aiPayload.subtitle ?? 'Clear message. Better results.';
		continue;
	}
	if (lowerKey.includes('myth') || lowerKey.includes('misconception')) {
		payload[key] =
			aiPayload.myth ?? aiPayloadByLower.myth ?? aiPayload.title ?? (goal ? goal.slice(0, 90) : 'Common misconception');
		continue;
	}
	if (lowerKey.includes('truth') || lowerKey.includes('reality') || lowerKey.includes('insight')) {
		payload[key] =
			aiPayload.truth ?? aiPayloadByLower.truth ?? aiPayload.subtitle ?? 'Clear message. Better results.';
		continue;
	}
	if (lowerKey.includes('text') || lowerKey.includes('body')) {
		payload[key] = aiPayload.body ?? aiPayload.text ?? goal;
	}
}

const genericPool = [
	aiPayload.title,
	aiPayload.subtitle,
	aiPayload.headline,
	aiPayload.tagline,
	aiPayload.body,
	aiPayload.text,
	aiPayload.myth,
	aiPayload.truth,
].filter((v) => v !== undefined && v !== null && str(v).trim() !== '');

let gi = 0;
for (const key of fieldKeys) {
	const missing = payload[key] === undefined || payload[key] === null || str(payload[key]).trim() === '';
	if (missing && gi < genericPool.length) {
		payload[key] = genericPool[gi];
		gi += 1;
	}
}

for (const key of fieldKeys) {
	const missing = payload[key] === undefined || payload[key] === null || str(payload[key]).trim() === '';
	if (missing) {
		payload[key] = goal ? goal.slice(0, 120) : '—';
	}
}

if (Object.keys(payload).length === 0 && fieldKeys.length && Object.keys(aiPayload).length > 0) {
	for (const key of fieldKeys) {
		const v = aiPayload[key] ?? aiPayloadByLower[String(key).toLowerCase()];
		if (v !== undefined && v !== null && str(v).trim() !== '') payload[key] = v;
	}
}

return [
	{
		json: {
			templateId: selectedTemplateId,
			themeVariant,
			payload,
			selectedTemplate,
			templatesCount: templates.length,
			aiRaw: aiText,
    inputPreset: source.preset ?? null,
		},
	},
];

const base = $('Choose Template').item.json;
const details = $input.first().json?.error?.details ?? [];
const payload = { ...(base.payload ?? {}) };
const st = base.selectedTemplate ?? {};
const rawFields = Array.isArray(st.fieldDefinitions)
  ? st.fieldDefinitions
  : Array.isArray(st.fields)
    ? st.fields
    : [];
const fieldKeys = rawFields.length
  ? rawFields.map((f) => f.key ?? f.name ?? f.id).filter(Boolean)
  : ['title', 'subtitle'];

for (const [key, value] of Object.entries(payload)) {
  if (typeof value === 'string' && value.length > 140) {
    payload[key] = `${value.slice(0, 137)}...`;
  }
}

for (const key of fieldKeys) {
  const missing = payload[key] === undefined || payload[key] === null || payload[key] === '';
  if (missing) {
    payload[key] = key.toLowerCase().includes('title') || key.toLowerCase().includes('myth')
      ? 'Untitled idea'
      : 'Auto-generated line';
  }
}

if (Object.keys(payload).length === 0 && fieldKeys.length) {
  for (let i = 0; i < fieldKeys.length; i++) {
    payload[fieldKeys[i]] = i === 0 ? 'Untitled idea' : 'Auto-generated line';
  }
}

return [{
  json: {
    templateId: base.templateId,
    themeVariant: base.themeVariant,
    payload,
    correctionReason: details,
  },
}];

const raw = $input.first().json ?? {};
const preset = String(raw.preset ?? 'myth-truth').trim().toLowerCase().replace(/\s+/g, '-');
const customGoal = String(raw.goal ?? '').trim();

const PRESETS = {
  'myth-truth': 'Create a social image that contrasts a myth about posting everywhere with the truth that one clear message beats noise everywhere.',
  'quote-card': 'Create a quote-card image with a punchy line about consistency and focus beating scattered hustle.',
  'hook-cover': 'Create a bold hook-cover image that stops the scroll and promises clarity over posting on every platform.',
  'educational': 'Create an educational slide that compresses why one channel with clear messaging beats thin posts across ten channels.',
  'problem-solution': 'Create a problem–solution image: the pain of being everywhere vs the relief of one sharp message.',
  'image-bullets': 'Create an image with 3 short bullets on focused messaging vs posting everywhere.',
  'proof-card': 'Create a proof-card style image with one credible stat or claim about message clarity and channel focus.',
  'custom': customGoal,
};

let goal = PRESETS[preset];
if (preset === 'custom') {
  goal = customGoal || PRESETS['myth-truth'];
} else if (!goal) {
  goal = customGoal || PRESETS['myth-truth'];
}

return [{
  json: {
    goal,
    preset: preset === 'custom' && customGoal ? 'custom' : preset,
    inputPreset: raw.preset ?? null,
  },
}];
